function executeClaim(step: Step, steps: Step[]): any {
  const referencedQuote = steps[step.policy];
  const policyItemTypes = referencedQuote.items.map((i: any) => i.type);
  for (const damage of step.incident.damages) {
    if (!policyItemTypes.includes(damage.itemType)) {
      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
    }
  }
  return claim({ policy: { items: referencedQuote.items }, incident: step.incident });
}
